949	{
950	    ngx_int_t             rc;
951	    ngx_stream_js_ctx_t  *ctx;
952	
953	    if (name->len == 0) {
954	        return NGX_DECLINED;
955	    }
956	
957	    ngx_log_debug0(NGX_LOG_DEBUG_STREAM, s->connection->log, 0,
958	                   "stream js phase handler");
959	
960	    rc = ngx_stream_js_init_vm(s, ngx_stream_js_session_proto_id);
961	    if (rc != NGX_OK) {
962	        return rc;
963	    }
964	
965	    ctx = ngx_stream_get_module_ctx(s, ngx_stream_js_module);
966	
967	    if (!ctx->in_progress) {
968	        /*
969	         * status is expected to be overriden by allow(), deny(), decline() or
970	         * done() methods.
971	         */
972	
973	        ctx->status = NGX_ERROR;
974	
975	        ngx_log_debug1(NGX_LOG_DEBUG_STREAM, ctx->log, 0,
976	                       "stream js phase call \"%V\"", name);
977	
978	        rc = ctx->engine->call((ngx_js_ctx_t *) ctx, name, &ctx->args[0], 1);
979	
980	        if (rc == NGX_ERROR) {
981	            return rc;
982	        }
983	    }
984	
985	    rc = ctx->run_event(s, ctx, &ctx->events[NGX_JS_EVENT_UPLOAD], 0);
986	    if (rc != NGX_OK) {
987	        return NGX_ERROR;
988	    }
989	
990	    if (ngx_stream_pending(ctx)) {
991	        ctx->in_progress = 1;
