993	                                                        ? NGX_AGAIN
994	                                                        : NGX_DONE;
995	
996	    } else {
997	        ctx->in_progress = 0;
998	        rc = ctx->status;
999	    }
1000	
1001	    ngx_log_debug1(NGX_LOG_DEBUG_STREAM, ctx->log, 0, "stream js phase rc: %i",
1002	                   rc);
1003	
1004	    return rc;
